## Match-3 Puzzle Game Pattern

Grid-based match-3 with swapping, cascade clearing, and scoring.

### Grid Data Structure
```typescript
const COLS = 8, ROWS = 8, TILE_SIZE = 64;
const GEMS = ['red', 'blue', 'green', 'yellow', 'purple'];
let grid: (string | null)[][] = [];

function initGrid() {
  for (let r = 0; r < ROWS; r++) {
    grid[r] = [];
    for (let c = 0; c < COLS; c++) {
      grid[r][c] = Phaser.Utils.Array.GetRandom(GEMS);
    }
  }
  // Re-roll until no initial matches
  while (findMatches().length > 0) initGrid();
}
```

### Match Detection
```typescript
function findMatches(): { r: number; c: number }[] {
  const matched: Set<string> = new Set();
  // Horizontal
  for (let r = 0; r < ROWS; r++) {
    for (let c = 0; c < COLS - 2; c++) {
      if (grid[r][c] && grid[r][c] === grid[r][c+1] && grid[r][c] === grid[r][c+2]) {
        matched.add(`${r},${c}`); matched.add(`${r},${c+1}`); matched.add(`${r},${c+2}`);
      }
    }
  }
  // Vertical (same pattern with rows)
  return [...matched].map(s => { const [r,c] = s.split(',').map(Number); return {r,c}; });
}
```

### Cascade & Fill
```typescript
function clearAndFill() {
  const matches = findMatches();
  matches.forEach(({r,c}) => grid[r][c] = null);
  // Drop tiles down
  for (let c = 0; c < COLS; c++) {
    let empty = ROWS - 1;
    for (let r = ROWS - 1; r >= 0; r--) {
      if (grid[r][c]) { grid[empty][c] = grid[r][c]; if (empty !== r) grid[r][c] = null; empty--; }
    }
    for (let r = empty; r >= 0; r--) grid[r][c] = Phaser.Utils.Array.GetRandom(GEMS);
  }
  // Recursively check for chain combos
  if (findMatches().length > 0) { comboCount++; clearAndFill(); }
}
```

### Tips
- Animate swaps with tweens before checking matches
- Combo multiplier: score *= comboCount for chain reactions
- Use `scene.tweens.add` for smooth gem falling animation

