### Deck Manager
```typescript
class DeckManager {
  deck: Card[] = []; hand: Card[] = []; discard: Card[] = [];
  shuffle() { Phaser.Utils.Array.Shuffle(this.deck); }
  draw(count: number) {
    for (let i = 0; i < count; i++) {
      if (this.deck.length === 0) { this.deck = [...this.discard]; this.discard = []; this.shuffle(); }
      if (this.deck.length > 0) this.hand.push(this.deck.pop()!);
    }
  }
  play(index: number): Card | null {
    if (index < 0 || index >= this.hand.length) return null;
    const card = this.hand.splice(index, 1)[0];
    this.discard.push(card);
    return card;
  }
  discardHand() { this.discard.push(...this.hand); this.hand = []; }
}
```

