### Inventory Manager
```typescript
interface Slot { itemId: string; count: number; }
class Inventory {
  slots: (Slot | null)[] = new Array(20).fill(null);
  add(itemId: string, count = 1): boolean {
    const def = ITEMS[itemId];
    if (def.stackable) {
      const existing = this.slots.find(s => s && s.itemId === itemId && s.count < def.maxStack);
      if (existing) { existing.count = Math.min(existing.count + count, def.maxStack); return true; }
    }
    const emptyIdx = this.slots.indexOf(null);
    if (emptyIdx === -1) return false; // inventory full
    this.slots[emptyIdx] = { itemId, count };
    return true;
  }
  remove(slotIdx: number, count = 1) {
    const slot = this.slots[slotIdx];
    if (!slot) return;
    slot.count -= count;
    if (slot.count <= 0) this.slots[slotIdx] = null;
  }
}
```

