const SAVE_KEY = 'mygame_save_';
function saveGame(slot: number, data: SaveData) {
  data.version = 1; data.timestamp = Date.now(); data.slot = slot;
  localStorage.setItem(SAVE_KEY + slot, JSON.stringify(data));
}
function loadGame(slot: number): SaveData | null {
  const raw = localStorage.getItem(SAVE_KEY + slot);
  if (!raw) return null;
  return JSON.parse(raw) as SaveData;
}
function deleteSave(slot: number) { localStorage.removeItem(SAVE_KEY + slot); }
function listSaves(): { slot: number; timestamp: number }[] {
  const saves: { slot: number; timestamp: number }[] = [];
  for (let i = 1; i <= 3; i++) {
    const d = loadGame(i);
    if (d) saves.push({ slot: i, timestamp: d.timestamp });
  }
  return saves;
}
