    apply: (s) => { s.shielded = true; }, remove: (s) => { s.shielded = false; } },
  extraLife: { id: 'extraLife', name: '+1 Life', duration: 0, stackable: true, icon: 'pu-life',
    apply: (s) => { s.lives += 1; } }
};
```

### Active Power-Up Manager
```typescript
const activePowerUps: Map<string, Phaser.Time.TimerEvent> = new Map();
function collectPowerUp(scene: Phaser.Scene, id: string) {
  const def = POWERUPS[id];
  if (!def.stackable && activePowerUps.has(id)) {
    activePowerUps.get(id)!.remove(); // refresh timer
  }
  def.apply(scene);
  if (def.duration > 0) {
    const timer = scene.time.delayedCall(def.duration, () => {
      def.remove?.(scene); activePowerUps.delete(id);
    });
    activePowerUps.set(id, timer);
  }
}
```

### Tips
- Show active power-ups with countdown icons in HUD
- Flash icon when <2s remaining
- Non-stackable power-ups should refresh duration on re-collect
- Spawn power-ups from destroyed enemies or hidden blocks

