## Leaderboard / High Score System

Local leaderboard with sorting, persistence, and display.

### Leaderboard Data
```typescript
interface ScoreEntry { name: string; score: number; date: number; level?: number; }
const STORAGE_KEY = 'mygame_leaderboard';
const MAX_ENTRIES = 10;

function getLeaderboard(): ScoreEntry[] {
  const raw = localStorage.getItem(STORAGE_KEY);
  return raw ? JSON.parse(raw) : [];
}
function addScore(entry: ScoreEntry) {
  const board = getLeaderboard();
  board.push(entry);
  board.sort((a, b) => b.score - a.score);
  if (board.length > MAX_ENTRIES) board.length = MAX_ENTRIES;
  localStorage.setItem(STORAGE_KEY, JSON.stringify(board));
}
function isHighScore(score: number): boolean {
  const board = getLeaderboard();
  return board.length < MAX_ENTRIES || score > board[board.length - 1].score;
}
```

### Display Scene
```typescript
create() {
  const { width } = this.scale;
  this.add.text(width / 2, 40, 'HIGH SCORES', { fontSize: '32px', color: '#ffd700' }).setOrigin(0.5);
