  board.forEach((entry, i) => {
    const y = 100 + i * 40;
    this.add.text(100, y, `${i + 1}.`, { fontSize: '20px', color: '#aaa' });
    this.add.text(140, y, entry.name, { fontSize: '20px', color: '#fff' });
    this.add.text(500, y, entry.score.toString(), { fontSize: '20px', color: '#4ade80' }).setOrigin(1, 0);
  });
}
```

### Tips
