## In-Game Tutorial / Onboarding System

Step-by-step tutorial with highlights and prompts.

### Tutorial Step Definition
```typescript
interface TutorialStep {
  id: string; message: string;
  highlightArea?: { x: number; y: number; w: number; h: number };
  waitFor: 'click' | 'key' | 'action'; action?: string;
}
const TUTORIAL: TutorialStep[] = [
  { id: 'move', message: 'Use arrow keys to move', waitFor: 'key' },
  { id: 'jump', message: 'Press SPACE to jump', waitFor: 'action', action: 'jump' },
  { id: 'collect', message: 'Walk into the coin to collect it', waitFor: 'action', action: 'collectCoin' },
];
```

### Tutorial Manager
```typescript
class TutorialManager {
  private stepIndex = 0; private overlay?: Phaser.GameObjects.Rectangle;
  private text?: Phaser.GameObjects.Text;
  constructor(private scene: Phaser.Scene) {}
  start() {
    if (localStorage.getItem('tutorial_done')) return;
    this.showStep();
  }
  showStep() {
    if (this.stepIndex >= TUTORIAL.length) { this.complete(); return; }
    const step = TUTORIAL[this.stepIndex];
    this.overlay = this.scene.add.rectangle(400, 300, 800, 600, 0x000000, 0.5).setScrollFactor(0).setDepth(998);
    this.text = this.scene.add.text(400, 500, step.message, {
      fontSize: '22px', color: '#fff', backgroundColor: '#333', padding: { x: 16, y: 8 }
    }).setOrigin(0.5).setScrollFactor(0).setDepth(999);
  }
  completeAction(action: string) {
    if (TUTORIAL[this.stepIndex]?.action === action) this.nextStep();
  }
  private nextStep() {
    this.overlay?.destroy(); this.text?.destroy();
    this.stepIndex++; this.showStep();
  }
  private complete() {
    localStorage.setItem('tutorial_done', '1');
    this.overlay?.destroy(); this.text?.destroy();
  }
}
```

### Tips
- Only show tutorial on first play; skip if `tutorial_done` flag set
- Use semi-transparent overlay to focus attention
- Keep messages short: 1-2 sentences max
- Pause game during tutorial steps for clarity

