### Send Player Input (not position)
```typescript
// Client sends inputs, server simulates
update() {
  const input = { left: cursors.left.isDown, right: cursors.right.isDown, jump: jumpPressed };
  if (inputChanged(input)) ws.send(JSON.stringify({ type: 'input', ...input }));
}
