});
```

### Wave Delay Pattern
```typescript
let wave = 0;
function startNextWave(scene: Phaser.Scene) {
  wave++;
  showWaveText(scene, `Wave ${wave}`);
  scene.time.delayedCall(2000, () => { // 2s prep time
    spawnWaveEnemies(wave);
  });
}
```

### Tips
- Use `this.time` not `setTimeout` — Phaser timers respect pause/timeScale
- Clean up timers in `shutdown()` to prevent ghost callbacks
- `time.addEvent` returns a TimerEvent you can pause/resume/remove
- For frame-accurate timing, use `update(time, delta)` with accumulator

## Spritesheet & Texture Atlas Guide

Efficient asset loading with spritesheets and texture atlases.

### Uniform Spritesheet (equal-size frames)
```typescript
preload() {
  this.load.spritesheet('player', 'assets/player-sheet.png', {
    frameWidth: 32, frameHeight: 48, startFrame: 0, endFrame: 15
  });
}
// Access frames by index
this.add.sprite(100, 100, 'player', 0); // first frame
```

### Texture Atlas (varied-size frames — JSON Hash)
```typescript
preload() {
  this.load.atlas('ui', 'assets/ui-atlas.png', 'assets/ui-atlas.json');
}
// Access frames by name
this.add.image(100, 100, 'ui', 'button-play');
this.add.image(200, 100, 'ui', 'icon-settings');
```

### Atlas JSON Format (JSON Hash)
```json
{
  "frames": {
    "button-play": { "frame": { "x": 0, "y": 0, "w": 128, "h": 48 } },
    "icon-settings": { "frame": { "x": 128, "y": 0, "w": 32, "h": 32 } }
  }
}
```

### Dynamic Frame from Code (no external image)
```typescript
// Generate a colored rectangle as texture
const gfx = this.make.graphics({ x: 0, y: 0 });
gfx.fillStyle(0x4ade80).fillRect(0, 0, 32, 32);
gfx.generateTexture('green-block', 32, 32);
gfx.destroy();
this.add.image(100, 100, 'green-block');
```

### Tips
- One atlas = one draw call; 50 separate images = 50 draw calls
- Use tools like TexturePacker or free ShoeBox to generate atlas JSON
- For animations, spritesheets are simpler; for mixed UI assets, atlas is better
- `generateTexture` is great for placeholder/debug graphics

## World Bounds & Screen Wrapping

Handle objects at screen edges: bounce, wrap, or destroy.

### Collide with World Bounds
```typescript
player.body!.setCollideWorldBounds(true);
player.body!.setBounce(0.2); // slight bounce on walls
```

### Custom World Size
```typescript
this.physics.world.setBounds(0, 0, 3200, 600); // wider than screen
this.cameras.main.setBounds(0, 0, 3200, 600);
```

### Screen Wrapping (Asteroids-style)
```typescript
update() {
  const { width, height } = this.scale;
  // Wrap player
  if (player.x < 0) player.x = width;
  if (player.x > width) player.x = 0;
  if (player.y < 0) player.y = height;
  if (player.y > height) player.y = 0;
}
// Or use Phaser's built-in:
this.physics.world.wrap(player, 16); // 16px padding
```

### Destroy Off-Screen Objects
```typescript
function recycleIfOffScreen(obj: Phaser.Physics.Arcade.Sprite, padding = 50) {
  const cam = obj.scene.cameras.main;
  if (obj.x < cam.scrollX - padding || obj.x > cam.scrollX + cam.width + padding ||
      obj.y < cam.scrollY - padding || obj.y > cam.scrollY + cam.height + padding) {
    obj.setActive(false).setVisible(false);
  }
}
```

### Bottom-Edge Death Zone
```typescript
// Platformer: fall off screen = die
update() {
  if (player.y > this.scale.height + 50) this.playerDie();
}
```

### Tips
- Use `setCollideWorldBounds(true)` for player, not for bullets/enemies
- Screen wrap is great for space/asteroids games
- Always recycle off-screen pooled objects to prevent memory leaks
- Set world bounds to match tilemap size for scrolling games
